UPDATE `quest_template` SET `entry`=745, `Method`=2, `ZoneOrSort`=215, `MinLevel`=1, `MaxLevel`=255, `QuestLevel`=6, `Type`=0, `RequiredClasses`=0, `RequiredRaces`=178, `RequiredSkill`=0, `RequiredSkillValue`=0, `RequiredCondition`=0, `RepObjectiveFaction`=0, `RepObjectiveValue`=0, `RequiredMinRepFaction`=0, `RequiredMinRepValue`=0, `RequiredMaxRepFaction`=0, `RequiredMaxRepValue`=0, `SuggestedPlayers`=0, `LimitTime`=0, `QuestFlags`=8, `SpecialFlags`=0, `PrevQuestId`=0, `NextQuestId`=0, `ExclusiveGroup`=0, `BreadcrumbForQuestId`=0, `NextQuestInChain`=0, `SrcItemId`=0, `SrcItemCount`=0, `SrcSpell`=0, `Title`='Sharing the Land', `Details`='$N, there are many conflicts that wound this land. It is my hope that you will not bear witness to as many of them as I have. Yet there is one that I would ask you to seek out. It will give you some sense of how terrible, if left unchecked, even a small threat can be to the land.$B$BPalemane gnolls have settled to the south of Bloodhoof and in a cave to the west. They disrespect our attempts to communicate with them, and they slay the wildlife of Mulgore unbridled.$B$BWords are no longer the answer.', `Objectives`='Kill 10 Palemane Tanners, 8 Palemane Skinners, and 5 Palemane Poachers, then return to Baine Bloodhoof in Bloodhoof Village.', `OfferRewardText`='$N, it is good you\'ve taken my task seriously. Respect of the land and its creatures is important. Death and life are a circle... a necessity. One cannot exist without the other. Take time to ponder this and do well to never forget it.', `RequestItemsText`='If the Palemanes had respected the land and its inhabitants more, this conflict would have never occurred.', `EndText`='', `ObjectiveText1`='', `ObjectiveText2`='', `ObjectiveText3`='', `ObjectiveText4`='', `ReqItemId1`=0, `ReqItemId2`=0, `ReqItemId3`=0, `ReqItemId4`=0, `ReqItemCount1`=0, `ReqItemCount2`=0, `ReqItemCount3`=0, `ReqItemCount4`=0, `ReqSourceId1`=0, `ReqSourceId2`=0, `ReqSourceId3`=0, `ReqSourceId4`=0, `ReqSourc